import 'package:flutter/material.dart';import '../../core/utils/date_time_utils.dart';import '../../core/widgets/empty_view.dart';import '../../core/widgets/loading_view.dart';import '../../services/winner_service.dart';
class WinnersScreen extends StatelessWidget{const WinnersScreen({super.key});@override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:const Text('Winners')),body:FutureBuilder(future:WinnerService().winners(),builder:(c,s){if(s.connectionState==ConnectionState.waiting)return const LoadingView();final list=s.data??[];if(list.isEmpty)return const EmptyView(message:'Winners will be announced soon.');return ListView.builder(padding:const EdgeInsets.all(12),itemCount:list.length,itemBuilder:(c,i){final w=list[i];return Card(child:ListTile(leading:const Icon(Icons.emoji_events,color:Colors.amber),title:Text(w.winnerName),subtitle:Text('${w.matchTitle}\n${w.prize??''} ${w.points==null?'':'• ${w.points} pts'}\n${DateTimeUtils.format(w.publishedAt)}')));});}));}
